import { useState } from 'react';
import {
  Card,
  Stack,
  Row,
  Text,
  Box,
} from '@ggui-ai/design/primitives';

interface ForecastItem {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: Array<{ day: string; icon: string; high: number; low: number }>;
}

export default function GeneratedComponent({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit,
  forecast,
}: Props) {
  // Map weather conditions to emoji/icons
  const getWeatherEmoji = (cond: string): string => {
    const condLower = cond.toLowerCase();
    if (condLower.includes('sunny') || condLower.includes('clear')) return '☀️';
    if (condLower.includes('cloudy') || condLower.includes('overcast')) return '☁️';
    if (condLower.includes('rainy') || condLower.includes('rain')) return '🌧️';
    if (condLower.includes('snow')) return '❄️';
    if (condLower.includes('storm') || condLower.includes('thunder')) return '⛈️';
    if (condLower.includes('fog') || condLower.includes('mist')) return '🌫️';
    if (condLower.includes('wind')) return '💨';
    return '🌤️'; // default
  };

  return (
    <Card
      padding="var(--ggui-spacing-6, 24px)"
      shadow="md"
      style={{
        background: `linear-gradient(135deg, var(--ggui-color-primary-50, #f0f9ff), var(--ggui-color-primary-100, #e0f2fe))`,
        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
      }}
    >
      <Stack direction="vertical" gap={24}>
        {/* Header: City and Current Temp */}
        <Stack direction="vertical" gap={8}>
          <Text
            variant="h2"
            color="var(--ggui-color-primary-900, #0c4a6e)"
            weight="bold"
          >
            {city}
          </Text>

          {/* Current Temperature Display */}
          <Stack direction="horizontal" align="center" gap={16}>
            <Text
              variant="h1"
              color="var(--ggui-color-primary-700, #0369a1)"
              weight="bold"
              style={{
                fontSize: 'var(--ggui-font-size-4xl, 36px)',
              }}
            >
              {temperature}°{unit}
            </Text>
            <Text
              variant="h3"
              color="var(--ggui-color-primary-600, #0284c7)"
              style={{
                fontSize: 'var(--ggui-font-size-3xl, 30px)',
              }}
            >
              {getWeatherEmoji(condition)}
            </Text>
          </Stack>

          {/* Weather Condition */}
          <Text
            variant="body"
            color="var(--ggui-color-primary-700, #0369a1)"
            weight="medium"
            style={{
              fontSize: 'var(--ggui-font-size-lg, 18px)',
            }}
          >
            {condition}
          </Text>
        </Stack>

        {/* Weather Details: Humidity and Wind Speed */}
        <Row gap={32} justify="start" align="center">
          {/* Humidity */}
          <Stack direction="vertical" gap={4}>
            <Text
              variant="label"
              color="var(--ggui-color-neutral-500, #6b7280)"
              weight="semibold"
            >
              Humidity
            </Text>
            <Text
              variant="h3"
              color="var(--ggui-color-primary-600, #0284c7)"
              weight="bold"
            >
              {humidity}%
            </Text>
          </Stack>

          {/* Wind Speed */}
          <Stack direction="vertical" gap={4}>
            <Text
              variant="label"
              color="var(--ggui-color-neutral-500, #6b7280)"
              weight="semibold"
            >
              Wind Speed
            </Text>
            <Text
              variant="h3"
              color="var(--ggui-color-primary-600, #0284c7)"
              weight="bold"
            >
              {windSpeed} {unit === 'F' ? 'mph' : 'km/h'}
            </Text>
          </Stack>
        </Row>

        {/* 5-Day Forecast Strip */}
        <Stack direction="vertical" gap={12}>
          <Text
            variant="label"
            color="var(--ggui-color-neutral-700, #374151)"
            weight="semibold"
            style={{
              fontSize: 'var(--ggui-font-size-sm, 14px)',
              textTransform: 'uppercase',
              letterSpacing: 'var(--ggui-spacing-1, 4px)',
            }}
          >
            5-Day Forecast
          </Text>

          {/* Forecast Items */}
          <Row
            gap={12}
            justify="start"
            align="stretch"
            wrap={true}
            style={{
              overflowX: 'auto',
              paddingBottom: 'var(--ggui-spacing-2, 8px)',
            }}
          >
            {forecast.map((item, index) => (
              <Box
                key={index}
                padding="var(--ggui-spacing-4, 16px)"
                borderRadius="var(--ggui-shape-radius-md, 8px)"
                background="rgba(255, 255, 255, 0.7)"
                style={{
                  minWidth: '100px',
                  flex: '0 0 auto',
                  border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                  textAlign: 'center',
                  backdropFilter: 'blur(4px)',
                }}
              >
                <Stack direction="vertical" gap={8} align="center">
                  {/* Day Name */}
                  <Text
                    variant="label"
                    color="var(--ggui-color-primary-700, #0369a1)"
                    weight="semibold"
                  >
                    {item.day}
                  </Text>

                  {/* Weather Icon */}
                  <Text
                    style={{
                      fontSize: 'var(--ggui-font-size-2xl, 24px)',
                    }}
                  >
                    {item.icon}
                  </Text>

                  {/* High/Low Temps */}
                  <Stack direction="horizontal" gap={8} justify="center" align="center">
                    <Text
                      variant="label"
                      color="var(--ggui-color-primary-600, #0284c7)"
                      weight="bold"
                    >
                      {item.high}°
                    </Text>
                    <Text
                      variant="caption"
                      color="var(--ggui-color-neutral-500, #6b7280)"
                    >
                      {item.low}°
                    </Text>
                  </Stack>
                </Stack>
              </Box>
            ))}
          </Row>
        </Stack>
      </Stack>
    </Card>
  );
}

import React from 'react';
import { Card, Stack, Text, Button } from '@ggui-ai/design/components';

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: Array<{ day: string; icon: string; high: number; low: number }>;
}

export default function WeatherCard(props: Props) {
