              </div>
            ))}
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}

/**
 * Helper function to map weather conditions to appropriate emojis
 */
function getWeatherEmoji(condition: string): string {
  const conditionLower = condition.toLowerCase();

  if (
    conditionLower.includes('sunny') ||
    conditionLower.includes('clear') ||
    conditionLower.includes('bright')
  ) {
    return '☀️';
  }
  if (
    conditionLower.includes('cloudy') ||
    conditionLower.includes('overcast') ||
    conditionLower.includes('cloud')
  ) {
    return '☁️';
  }
  if (
    conditionLower.includes('rainy') ||
    conditionLower.includes('rain') ||
    conditionLower.includes('drizzle')
  ) {
    return '🌧️';
  }
  if (conditionLower.includes('snow') || conditionLower.includes('snowy')) {
    return '❄️';
  }
  if (conditionLower.includes('storm') || conditionLower.includes('thunder')) {
    return '⛈️';
  }
  if (conditionLower.includes('fog') || conditionLower.includes('mist')) {
    return '🌫️';
  }
  if (conditionLower.includes('wind') || conditionLower.includes('windy')) {
    return '💨';
  }
  if (conditionLower.includes('night') || conditionLower.includes('dark')) {
    return '🌙';
  }

  // Default fallback
  return '🌤️';
}

