  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: ForecastItem[];
}

/**
 * Maps common weather condition strings to emojis.
 */
const WeatherIcon = ({ condition }: { condition: string }) => {
  const iconMap: Record<string, string> = {
    sunny: '☀️',
    clear: '☀️',
    cloudy: '☁️',
    partly_cloudy: '⛅',
    rainy: '🌧️',
    stormy: '⛈️',
    snowy: '❄️',
    mist: '🌫️',
    fog: '🌫️',
  };

  const normalized = condition.toLowerCase().replace(/\s+/g, '_');
  return <span aria-hidden="true" style={{ fontSize: '1.2em' }}>{iconMap[normalized] || '🌡️'}</span>;
};

